  { word: "transparent", phonetic: "/trænsˈpærənt/", meaning: "adj. 透明的，清晰的", examples: [{ en: "The government promised to make the decision-making process transparent.", zh: "政府承诺使决策过程透明。" }, { en: "Transparent communication builds trust between managers and employees.", zh: "透明的沟通建立管理者与员工之间的信任。" }], memoryTip: "trans(穿过)+parent(出现) → 穿过去看到的 → 透明的" },
  { word: "trigger", phonetic: "/ˈtrɪɡər/", meaning: "v. 触发，引起", examples: [{ en: "Certain foods can trigger allergic reactions in sensitive individuals.", zh: "某些食物可能触发敏感人群的过敏反应。" }, { en: "The announcement triggered a sharp decline in stock prices.", zh: "这一公告引发了股价的急剧下跌。" }], memoryTip: "trigger(扳机) → 扣扳机 → 触发" },
  { word: "trivial", phonetic: "/ˈtrɪviəl/", meaning: "adj. 琐碎的，微不足道的", examples: [{ en: "The committee spent too much time on trivial matters.", zh: "委员会在琐碎的事情上花了太多时间。" }, { en: "Although the error seemed trivial, it had serious consequences.", zh: "虽然错误看似微不足道，却导致了严重后果。" }], memoryTip: "tri(三)+vi(路)+al → 三条路交叉的 → 小事的" },
  { word: "ultimatum", phonetic: "/ˌʌltɪˈmeɪtəm/", meaning: "n. 最后通牒", examples: [{ en: "The union issued an ultimatum to management before the strike.", zh: "工会在罢工前向管理层发出了最后通牒。" }, { en: "The ultimatum demanded an immediate response from the government.", zh: "最后通牒要求政府立即回应。" }], memoryTip: "ultim(最后的)+atum → 最后的话 → 最后通牒" },
  { word: "underestimate", phonetic: "/ˌʌndərˈestɪmeɪt/", meaning: "v. 低估，看轻", examples: [{ en: "People often underestimate the time required for complex projects.", zh: "人们常常低估复杂项目所需的时间。" }, { en: "The impact of social media on political discourse should not be underestimated.", zh: "社交媒体对政治话语的影响不应被低估。" }], memoryTip: "under(下)+estimate(估计) → 估计低了 → 低估" },
  { word: "underlying", phonetic: "/ˌʌndərˈlaɪɪŋ/", meaning: "adj. 潜在的，根本的", examples: [{ en: "We need to address the underlying causes of the problem.", zh: "我们需要解决问题的根本原因。" }, { en: "The underlying assumption of the theory is questionable.", zh: "该理论的潜在假设值得怀疑。" }], memoryTip: "under(下)+ly(躺)+ing → 躺在下面的 → 潜在的" },
  { word: "undermine", phonetic: "/ˌʌndərˈmaɪn/", meaning: "v. 削弱，破坏", examples: [{ en: "Corruption undermines public trust in government institutions.", zh: "腐败削弱了公众对政府机构的信任。" }, { en: "Constant criticism can undermine a child's confidence.", zh: "不断的批评会损害孩子的自信心。" }], memoryTip: "under(下)+mine(挖) → 在下面挖 → 削弱" },
  { word: "uniformity", phonetic: "/ˌjuːnɪˈfɔːrməti/", meaning: "n. 一致性，统一性", examples: [{ en: "The standardization ensures uniformity across all branches.", zh: "标准化确保所有分支的一致性。" }, { en: "Cultural uniformity can result from globalization.", zh: "文化一致性可能源于全球化。" }], memoryTip: "uni(一个)+form(形式)+ity → 一个形式 → 一致性" },
  { word: "unprecedented", phonetic: "/ʌnˈpresɪdentɪd/", meaning: "adj. 史无前例的，空前的", examples: [{ en: "The pandemic led to unprecedented global economic disruption.", zh: "疫情导致了史无前例的全球经济混乱。" }, { en: "The scale of the natural disaster was unprecedented in modern history.", zh: "自然灾害的规模在现代史上是空前的。" }], memoryTip: "un(不)+precedent(先例)+ed → 没有先例的 → 史无前例的" },
  { word: "validate", phonetic: "/ˈvælɪdeɪt/", meaning: "v. 验证，确认", examples: [{ en: "Experiments are conducted to validate the scientific hypothesis.", zh: "进行实验以验证科学假说。" }, { en: "The results were validated by an independent research team.", zh: "结果由一个独立研究团队验证。" }], memoryTip: "valid(有效的)+ate → 使有效 → 验证" },
  { word: "variable", phonetic: "/ˈveəriəbl/", meaning: "n. 变量；adj. 可变的", examples: [{ en: "Temperature is a key variable in the experiment.", zh: "温度是实验中的一个关键变量。" }, { en: "The weather in this region is highly variable.", zh: "该地区的天气变化很大。" }], memoryTip: "vari(变化)+able(能) → 能变化的 → 变量" },
  { word: "verbal", phonetic: "/ˈvɜːrbl/", meaning: "adj. 言语的，口头的", examples: [{ en: "The study focuses on verbal communication in cross-cultural contexts.", zh: "该研究关注跨文化语境中的言语交流。" }, { en: "The contract includes both verbal and written agreements.", zh: "合同既包括口头协议也包括书面协议。" }], memoryTip: "verb(词语)+al → 词语的 → 言语的" },
  { word: "versatile", phonetic: "/ˈvɜːrsətl/", meaning: "adj. 多才多艺的，多功能的", examples: [{ en: "She is a versatile musician who plays multiple instruments.", zh: "她是一位多才多艺的音乐家，会演奏多种乐器。" }, { en: "The versatile device can be used for both work and entertainment.", zh: "这个多功能设备可用于工作和娱乐。" }], memoryTip: "vers(转)+at+ile → 能转来转去的 → 多功能的" },
  { word: "viable", phonetic: "/ˈvaɪəbl/", meaning: "adj. 可行的，能存活的", examples: [{ en: "Solar energy is a viable alternative to fossil fuels.", zh: "太阳能是化石燃料可行的替代方案。" }, { en: "The business model proved viable in the current market.", zh: "该商业模式在当今市场中被证明是可行的。" }], memoryTip: "vi(路)+able(能) → 能上路的一可行的" },
  { word: "vindicate", phonetic: "/ˈvɪndɪkeɪt/", meaning: "v. 证明…正确，辩护", examples: [{ en: "Later discoveries vindicated the scientist's controversial theory.", zh: "后来的发现证明了这位科学家有争议的理论是正确的。" }, { en: "The investigation vindicated the accused of all charges.", zh: "调查证明被告的所有指控都是不实的。" }], memoryTip: "vin(力量)+dic(说)+ate → 用力量说话 → 证明正确" },
  { word: "volatile", phonetic: "/ˈvɒlətaɪl/", meaning: "adj. 不稳定的，易变的", examples: [{ en: "The stock market has been particularly volatile this quarter.", zh: "本季度股票市场特别不稳定。" }, { en: "Political instability makes the region volatile.", zh: "政治不稳定使该地区局势动荡。" }], memoryTip: "vol(飞)+at+ile → 能飞走的一不稳定的" },
  { word: "warrant", phonetic: "/ˈwɒrənt/", meaning: "v. 证明…正当；n. 授权", examples: [{ en: "The severity of the problem warrants immediate action.", zh: "问题的严重性证明立即采取行动是正当的。" }, { en: "The evidence does not warrant such a strong conclusion.", zh: "证据并不支持如此强烈的结论。" }], memoryTip: "warr(保证)+ant → 保证其正当性 → 证明正当" },
  { word: "yield", phonetic: "/jiːld/", meaning: "v. 产生；屈服；n. 产量", examples: [{ en: "The investment yielded a high rate of return.", zh: "这项投资产生了高回报率。" }, { en: "The research yielded significant insights into the disease.", zh: "这项研究对该疾病产生了重要的见解。" }], memoryTip: "yield(田地) → 土地上出产东西 → 产量" }
